diff --git a/arrow-cast/src/cast/decimal.rs b/arrow-cast/src/cast/decimal.rs
index 57dfc51d7..f8d2f143c 100644
--- a/arrow-cast/src/cast/decimal.rs
+++ b/arrow-cast/src/cast/decimal.rs
@@ -29,6 +29,68 @@ pub(crate) trait DecimalCast: Sized {
     fn from_f64(n: f64) -> Option<Self>;
 }

+impl DecimalCast for i32 {
+    fn to_i128(self) -> Option<i128> {
+        Some(self as i128)
+    }
+
+    fn to_i256(self) -> Option<i256> {
+        Some(i256::from_i128(self as i128))
+    }
+
+    fn from_decimal<T: DecimalCast>(n: T) -> Option<Self> {
+        n.to_i128().and_then(|v| {
+            if v >= i32::MIN as i128 && v <= i32::MAX as i128 {
+                Some(v as i32)
+            } else {
+                None
+            }
+        })
+    }
+
+    fn from_f64(n: f64) -> Option<Self> {
+        // Use to_i128 for conversion to maintain consistency with other implementations
+        n.to_i128().and_then(|v| {
+            if v >= i32::MIN as i128 && v <= i32::MAX as i128 {
+                Some(v as i32)
+            } else {
+                None
+            }
+        })
+    }
+}
+
+impl DecimalCast for i64 {
+    fn to_i128(self) -> Option<i128> {
+        Some(self as i128)
+    }
+
+    fn to_i256(self) -> Option<i256> {
+        Some(i256::from_i128(self as i128))
+    }
+
+    fn from_decimal<T: DecimalCast>(n: T) -> Option<Self> {
+        n.to_i128().and_then(|v| {
+            if v >= i64::MIN as i128 && v <= i64::MAX as i128 {
+                Some(v as i64)
+            } else {
+                None
+            }
+        })
+    }
+
+    fn from_f64(n: f64) -> Option<Self> {
+        // Use to_i128 for conversion to maintain consistency with other implementations
+        n.to_i128().and_then(|v| {
+            if v >= i64::MIN as i128 && v <= i64::MAX as i128 {
+                Some(v as i64)
+            } else {
+                None
+            }
+        })
+    }
+}
+
 impl DecimalCast for i128 {
