   631→///             DataType::Utf8 => {
   632→///                 for v in array.downcast::<StringArray>().unwrap() {
   633→///                     println!("{:?}", v);
   634→///                 }
   635→///             }
   636→///             t => println!("Unsupported run array value type {}", t),
   637→///         },
   638→///         DataType::Utf8 => {
   639→///             for v in as_string_array(array) {
   640→///                 println!("{:?}", v);
   641→///             }
   642→///         }
