   644→///         DataType::LargeUtf8 if true => {
   645→///             for v in as_largestring_array(array) {
   646→///                 println!("{:?}", v);
   647→///             }
   648→///         }
   649→///         t => println!("Unsupported datatype {}", t)
   650→///     )
   651→/// }
