    let decimal32_arr = Decimal32Array::from(vec![12345]).with_precision_and_scale(5, 2).unwrap();

    // Test casting Decimal32 to Decimal64
    match cast(&decimal32_arr, &DataType::Decimal64(5, 2), &CastOptions::default()) {
